query_schema:
query ListDatasets($first: Int, $after: String) {
  datasets(first: $first, after: $after) {
    edges {
      node {
        id
        created
        name
        public
        publishDate
        analytics { downloads views }
        latestSnapshot {
          id
          summary { modalities subjects totalFiles size primaryModality }
          description { Name BIDSVersion License Authors DatasetDOI }
        }
      }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query GetDataset($datasetId: ID!) {
  dataset(id: $datasetId) {
    id
    created
    name
    public
    publishDate
    analytics { downloads views }
    latestSnapshot {
      id
      tag
      created
      size
      summary { modalities subjects tasks totalFiles size primaryModality sessions }
      description { Name BIDSVersion License Authors Funding ReferencesAndLinks DatasetDOI EthicsApprovals }
      readme
    }
    stars { userId }
  }
}

query GetSnapshots($datasetId: ID!) {
  dataset(id: $datasetId) {
    id
    name
    snapshots {
      id
      tag
      created
      size
      summary { modalities subjects totalFiles size }
      description { Name BIDSVersion Authors }
    }
  }
}

query SearchByModality($first: Int, $modality: String) {
  datasets(first: $first, modality: $modality, orderBy: {created: descending}) {
    edges {
      node {
        id
        created
        name
        public
      }
    }
    pageInfo { count }
  }
}
